class Solution:
    def maximumTastiness(self, price, k):
        """
        :type price: List[int]
        :type k: int
        :rtype: int
        """
        price.sort()

        def canAchieve(min_diff):
            # Check if we can select k candies with min difference >= min_diff
            count = 1
            last = price[0]

            for i in range(1, len(price)):
                if price[i] - last >= min_diff:
                    count += 1
                    last = price[i]
                    if count == k:
                        return True

            return count >= k

        left, right = 0, price[-1] - price[0]
        result = 0

        while left <= right:
            mid = (left + right) // 2
            if canAchieve(mid):
                result = mid
                left = mid + 1
            else:
                right = mid - 1

        return result
